#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding hormone-replacement-therapy-assessment (16 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    ethnicity:string! \
    primary_language:string! \
    interpreter_required:string! \
    marital_status:string! \
    occupation:string! \
    smoking_status:string! \
    alcohol_units_per_week:int \
    exercise_frequency:string! \
    emergency_contact_name:string! \
    emergency_contact_phone:string! \
    gp_name:string! \
    gp_practice:string! \
    --htmx

cargo loco generate scaffold assessment_menopause_status \
    assessment:references \
    menopausal_status:string! \
    age_at_menopause:int \
    premature_menopause:string! \
    last_menstrual_period_date:date \
    menstrual_status:string! \
    cycle_changes:text! \
    surgical_menopause_type:string! \
    surgical_menopause_date:date \
    fsh_level:double \
    oestradiol_level:double \
    hormone_testing_date:date \
    menopause_duration_years:int \
    menopause_status_notes:text! \
    --htmx

cargo loco generate scaffold assessment_mrs_symptom_scale \
    assessment:references \
    hot_flushes_sweating:int \
    heart_discomfort:int \
    sleep_problems:int \
    joint_muscle_discomfort:int \
    depressive_mood:int \
    irritability:int \
    anxiety:int \
    physical_mental_exhaustion:int \
    sexual_problems:int \
    bladder_problems:int \
    dryness_of_vagina:int \
    somatic_subscale_score:int \
    psychological_subscale_score:int \
    urogenital_subscale_score:int \
    mrs_total_score:int \
    --htmx

cargo loco generate scaffold assessment_vasomotor_symptoms \
    assessment:references \
    hot_flushes_present:string! \
    hot_flush_frequency:string! \
    hot_flush_severity:int \
    hot_flush_duration_minutes:int \
    night_sweats:string! \
    night_sweat_frequency:string! \
    sleep_disruption:string! \
    sleep_disruption_severity:int \
    palpitations:string! \
    impact_on_work:string! \
    impact_on_social_life:string! \
    previous_vasomotor_treatment:string! \
    previous_treatment_details:text! \
    vasomotor_notes:text! \
    --htmx

cargo loco generate scaffold assessment_bone_health \
    assessment:references \
    previous_fracture:string! \
    fracture_details:text! \
    fragility_fracture:string! \
    family_history_osteoporosis:string! \
    family_history_hip_fracture:string! \
    dexa_scan_performed:string! \
    dexa_scan_date:date \
    spine_t_score:double \
    hip_t_score:double \
    dexa_result:string! \
    calcium_intake:string! \
    vitamin_d_level:double \
    vitamin_d_supplementation:string! \
    corticosteroid_use:string! \
    corticosteroid_details:text! \
    frax_score:double \
    bone_health_notes:text! \
    --htmx

cargo loco generate scaffold assessment_cardiovascular_risk \
    assessment:references \
    has_hypertension:string! \
    systolic_bp_mmhg:int \
    diastolic_bp_mmhg:int \
    on_antihypertensive:string! \
    has_diabetes:string! \
    diabetes_type:string! \
    hba1c:double \
    total_cholesterol:double \
    hdl_cholesterol:double \
    ldl_cholesterol:double \
    triglycerides:double \
    on_statin:string! \
    history_of_vte:string! \
    vte_details:text! \
    history_of_stroke_tia:string! \
    history_of_mi:string! \
    family_history_cvd:string! \
    qrisk3_score:double \
    cardiovascular_notes:text! \
    --htmx

cargo loco generate scaffold assessment_breast_health \
    assessment:references \
    personal_history_breast_cancer:string! \
    breast_cancer_details:text! \
    breast_cancer_treatment:text! \
    family_history_breast_cancer:string! \
    family_breast_cancer_details:text! \
    family_history_ovarian_cancer:string! \
    known_brca_mutation:string! \
    brca_mutation_type:string! \
    mammogram_up_to_date:string! \
    last_mammogram_date:date \
    mammogram_result:string! \
    breast_biopsy_history:string! \
    breast_biopsy_details:text! \
    breast_density:string! \
    current_breast_symptoms:string! \
    breast_symptom_details:text! \
    breast_health_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    takes_regular_medications:string! \
    current_hrt:string! \
    current_hrt_type:string! \
    current_hrt_route:string! \
    current_hrt_duration:string! \
    previous_hrt:string! \
    previous_hrt_details:text! \
    reason_for_stopping_hrt:text! \
    takes_herbal_supplements:string! \
    herbal_supplement_details:text! \
    takes_anticoagulants:string! \
    anticoagulant_details:text! \
    medication_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_medication_item \
    current_medications:references \
    medication_name:string! \
    dose:string! \
    frequency:string! \
    indication:string! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_contraindications_screen \
    assessment:references \
    undiagnosed_vaginal_bleeding:string! \
    known_or_suspected_breast_cancer:string! \
    known_or_suspected_oestrogen_dependent_neoplasm:string! \
    active_or_recent_vte:string! \
    active_or_recent_arterial_thromboembolism:string! \
    untreated_endometrial_hyperplasia:string! \
    active_liver_disease:string! \
    porphyria:string! \
    known_pregnancy:string! \
    history_of_endometrial_cancer:string! \
    history_of_vte:string! \
    thrombophilia:string! \
    migraine_with_aura:string! \
    gallbladder_disease:string! \
    epilepsy:string! \
    sle:string! \
    meningioma:string! \
    absolute_contraindication_present:string! \
    relative_contraindication_present:string! \
    contraindication_notes:text! \
    --htmx

cargo loco generate scaffold assessment_treatment_preferences \
    assessment:references \
    preferred_hrt_route:string! \
    has_uterus:string! \
    combined_hrt_appropriate:string! \
    preferred_regimen:string! \
    interested_in_testosterone:string! \
    testosterone_details:text! \
    interested_in_vaginal_oestrogen:string! \
    non_hormonal_alternatives_considered:string! \
    non_hormonal_details:text! \
    concerns_about_hrt:text! \
    duration_expectation:string! \
    follow_up_preference:string! \
    informed_consent_discussed:string! \
    patient_information_provided:string! \
    treatment_preference_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    mrs_total_score:int! \
    somatic_subscale_score:int! \
    psychological_subscale_score:int! \
    urogenital_subscale_score:int! \
    overall_severity:string! \
    hrt_eligibility:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
